// Get country data by ID
window.getCountryData = function(countryId) {
    return window.carspecio_COUNTRIES[countryId] || null;
};

// Get all countries
window.getAllCountries = function() {
    return Object.keys(window.carspecio_COUNTRIES).map(id => ({
        id: id,
        ...window.carspecio_COUNTRIES[id]
    }));
};

// Get regions for a country
window.getCountryRegions = function(countryId) {
    const country = window.carspecio_COUNTRIES[countryId];
    return country ? country.regions : [];
};
